Hi @cdhd2!

I'm not quite sure what you mean by "passed the 'data' object to the sheet_from_array_of_arrays method".

Basically, the `output_callback` is always passed a string. So if you set the `output_separator` to be `array` then use `JSON.parse` in the output callback you'll get a nice array of arrays ([demo](http://jsfiddle.net/Mottie/abkNM/7734/)):

```js
$(function() {

  var $table = $('table');

  $('.download').click(function() {
    $table.trigger('outputTable');
  });

  $table.tablesorter({
    theme: 'blue',
    widgets: ['zebra', 'output'],
    widgetOptions: {
      output_separator: 'array',
      output_callback: function(config, data) {
        var result = JSON.parse(data);
        console.log($.isArray(result), result);
      }
    }
  });
});
```

