I thought about this a little more and I can get the behavior i'm looking for by creating my own dictionary instead of changing the `ObjectProxy`:

```python

import collections
import wrapt

class ProxyDict(collections.MutableMapping):
    def __init__(self):
        self._data = {}

    def __getitem__(self, key):
        return self._data[key]

    def __setitem__(self, key, value):
        if key in self._data:
            self._data[key].__wrapped__ = value
        else:
            self._data[key] = wrapt.ObjectProxy(value)

    def __delitem__(self, key):
        del self._data[key]

    def __iter__(self):
        return iter(self._data)

    def __len__(self):
        return len(self._data)

d = ProxyDict()
d['a'] = 'foo'
val = d['a']
print(val) # foo
d['a'] = 'bar'
print(val) # bar
```

